/// @brief  Return the product of the vector `x` with every odd indexed
///         element inverted:  x0 * 1/x1 * x2 * 1/x3 * ...
/// @note   Exact behavior of the original function is preserved.
inline double productWithInverses(const std::vector<double> &x) {
    const std::size_t n = x.size();

    // Handle trivial cases early
    if (n == 0) return 1.0;
    if (n == 1) return x[0];

    double product = 1.0;

    // Parallel reduction with a custom combine function
