/* Return the largest sum of any contiguous subarray in the vector x.
   i.e. if x=[−2, 1, −3, 4, −1, 2, 1, −5, 4] then [4, −1, 2, 1] is the contiguous
   subarray with the largest sum of 6.
   Example:
   input: [−2, 1, −3, 4, −1, 2, 1, −5, 4]
   output: 6
*/
inline int maximumSubarray(std::vector<int> const& x) {
    // Kadane’s algorithm – O(n) time, O(1) space
    int best = std::numeric_limits<int>::lowest();
    int current = 0;
    for (int val : x) {
        // Accumulate current sum, dropping negative sums
        current = std::max(val, current + val);
        best = std::max(best, current);
    }
    return best;
}
