#include <limits>
#include <omp.h>

/* Return the value of the smallest odd number in the vector x.
   Examples:
   input: [7, 9, 5, 2, 8, 16, 4, 1]   → 1
   input: [8, 36, 7, 2, 11]          → 7
*/
inline int smallestOdd(std::vector<int> const& x)
{
    // If the vector is empty we return max int (same as original behaviour)
    if (x.empty()) return std::numeric_limits<int>::max();

    // Use an OpenMP parallel reduction with a custom local accumulator.
    // Each thread keeps the best odd seen so far.
    int global_min = std::numeric_limits<int>::max();

    #pragma omp parallel
    {
        int local_min = std::numeric_limits<int>::max();

        #pragma omp for nowait
        for (size_t i = 0; i < x.size(); ++i) {
            int v = x[i];
            if ((v & 1) && v < local_min) local_min = v;
        }

        // Combine the local minima into the global one.
        #pragma omp atomic min
        if (local_min < global_min) global_min = local_min;
    }

    return global_min;
}
