int64_t sumOfPrefixSum(const std::vector<int64_t>& x) {
    const std::size_t n = x.size();
    int64_t result = 0;

    // Parallel reduction using the identity:  Σ_{k=0}^{n-1} Σ_{j=0}^{k} x[j]
