25_reduce_xor:
```cpp
#pragma once
#include <vector>

/* Return the logical XOR reduction of the vector of bools x.
   Example:
   input: [false, false, false, true]
   output: true
*/
inline bool reduceLogicalXOR(const std::vector<bool>& x)
{
    // Fast XOR reduction by processing 64 bits at a time using the packed
    // representation of std::vector<bool>.
    const std::size_t n_bits = x.size();
    const std::size_t n_chunks = n_bits / 64;
    const std::size_t remaining = n_bits % 64;

    // Obtain the underlying bitset representation
    const std::vector<bool>::reference* base = &x[0];
    const unsigned long long* bits = reinterpret_cast<const unsigned long long*>(base);

    unsigned long long acc = 0ull;

    // Process full 64‑bit chunks
    for (std::size_t i = 0; i < n_chunks; ++i) {
        acc ^= bits[i];
    }

    // Process any remaining bits
    if (remaining) {
        unsigned long long mask = (1ull << remaining) - 1;
        unsigned long long tail = bits[n_chunks] & mask;
        acc ^= tail;
    }

    // The overall XOR is true if the number of set bits in acc is odd.
    return (std::popcount(acc) & 1) != 0;
}
```

