/// Bins are stored in ``bins``.  Values are guaranteed to be in [0,100].
void binsBy10Count(std::vector<double> const& x, std::array<size_t, 10> &bins) {
    // Reset bins
    for (auto& v : bins) v = 0;

    // Temporary per‑thread bins for local accumulations
    int const nthreads = omp_get_max_threads();
    std::vector<std::array<size_t, 10>> local_bins(nthreads);
    for (int t = 0; t < nthreads; ++t)
        for (auto& v : local_bins[t]) v = 0;

    // Parallel loop, each thread uses its local bins
#pragma omp parallel
    {
        int const tid = omp_get_thread_num();
        auto &local = local_bins[tid];
#pragma omp for schedule(static)
        for (size_t i = 0; i < x.size(); ++i) {
            const size_t bin = static_cast<size_t>(x[i]) / 10;   // 0‑9
            ++local[bin];
        }
