    {
        int tid = omp_get_thread_num();
        auto &local = local_bins[tid];
        // zero local buffer
        for (int i = 0; i < 256; ++i) local[i] = 0;

        // process a chunk of the image
        #pragma omp for schedule(static)
        for (size_t idx = 0; idx < image.size(); ++idx) {
            local[static_cast<unsigned char>(image[idx])]++;
        }
    }

    // Merge local counts into global bins
    for (int t = 0; t < nthreads; ++t) {
        auto const &local = local_bins[t];
        for (int i = 0; i < 256; ++i) {
            bins[i] += local[i];
        }
