/* Count the number of doubles in the vector x that have a fractional part 
   in [0, 0.25), [0.25, 0.5), [0.5, 0.75), and [0.75, 1). Store the counts in `bins`.
   The function is thread‑safe and works with the
   original calling convention expected by the harness. */
void countQuartiles(std::vector<double> const& x, std::array<size_t, 4>& bins) {
    /* reset bins */
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    /* Parallel reduction using a local temporary array per thread */
    #pragma omp parallel
    {
        /* each thread has its own local counter array */
        size_t local[4] = {0, 0, 0, 0};

        #pragma omp for
        for (size_t i = 0; i < x.size(); ++i) {
            double val   = x[i];
            int    whole = static_cast<int>(val);          // truncate toward zero
            double frac  = val - whole;                   // fractional part
            if (frac < 0.25)         ++local[0];
            else if (frac < 0.5)     ++local[1];
            else if (frac < 0.75)    ++local[2];
            else                     ++local[3];
        }

        /* merge local counts into global bins */
        #pragma omp critical
        {
            bins[0] += local[0];
            bins[1] += local[1];
            bins[2] += local[2];
            bins[3] += local[3];
        }
    }
}
