        const double x = points[i].x;
        const double y = points[i].y;

        if (x >= 0.0) {
            if (y >= 0.0) {
                ++bins[0];
            } else {
                ++bins[3];
            }
        } else {
            if (y >= 0.0) {
                ++bins[1];
            } else {
                ++bins[2];
            }
        }
    }
