19_graph_shortest_path:
```cpp
#pragma once
#include <vector>
#include <limits>
#include <cstddef>
#include <cstdint>

/* Return the length of the shortest path from source to dest in the undirected graph
   defined by the adjacency matrix A.  A is an N×N matrix stored in row‑major order.
   The function assumes the graph is connected. */
static inline int shortestPathLength(std::vector<int> const& A, std::size_t N,
                                     int source, int dest)
{
    // A simple BFS using a circular buffer.
    // Use a raw array for the queue to avoid std::queue overhead.
    std::vector<char> visited(N, 0);
    std::vector<int>   qnode(N);
    std::vector<int>   qdist(N);

    std::size_t head = 0, tail = 0;
    visited[source] = 1;
    qnode[tail] = source;
    qdist[tail] = 0;
    ++tail; // queue size is tail - head

    while (head != tail) {
        int curNode = qnode[head];
        int curDist = qdist[head];
        ++head; // pop front

        if (curNode == dest)
            return curDist;

        std::size_t rowOffset = curNode * N;
        for (std::size_t i = 0; i < N; ++i) {
            if (A[rowOffset + i] && !visited[i]) {
                visited[i] = 1;
                qnode[tail] = static_cast<int>(i);
                qdist[tail] = curDist + 1;
                ++tail; // push back
            }
        }
    }

    // Graph is guaranteed to be connected, but return max int if not found.
    return std::numeric_limits<int>::max();
}
