   A is an NxN adjacency matrix stored in row-major. 
   The function is thread‑safe and uses OpenMP for parallel speedup. */
int maxDegree(const std::vector<int>& A, std::size_t N)
{
    int highestDegree = 0;

    #pragma omp parallel
    {
        int localMax = 0;

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < N; ++i) {
