#pragma once
#include <vector>
#include <atomic>

/* Union ­Find with path compression and union by rank.
   It works on an arbitrary number of elements (>=1). */
struct UF {
    std::vector<int> parent, rank;

    explicit UF(std::size_t n)
        : parent(n), rank(n, 0) {
        for (std::size_t i = 0; i < n; ++i) parent[i] = static_cast<int>(i);
    }

    /* Find the root of x with path compression. */
    int find(int x) noexcept {
        int r = parent[x];
        if (r != x) {
            parent[x] = find(r);   // Path compression
            r = parent[x];
        }
        return r;
    }

    /* Union two sets. Returns true if a merge happened. */
    bool unite(int a, int b) noexcept {
        int ra = find(a);
        int rb = find(b);
        if (ra == rb) return false;

        /* union by rank */
        if (rank[ra] < rank[rb]) std::swap(ra, rb);
        parent[rb] = ra;
        if (rank[ra] == rank[rb]) ++rank[ra];
        return true;
    }
};

/* Count the number of connected components in the undirected graph
   defined by the adjacency matrix A (row‑major).  The algorithm
   uses a parallel union‑find to combine all edges. */
int componentCount(std::vector<int> const& A, std::size_t N) {
    UF uf(N);
    std::atomic<int> comps{static_cast<int>(N)};

    /* Parallel scan over the upper triangle of the adjacency matrix.
       Only consider the part where i < j to avoid duplicate work. */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        for (std::size_t j = i + 1; j < N; ++j) {
            if (A[i * N + j]) {          // Edge exists
                if (uf.unite(static_cast<int>(i), static_cast<int>(j)))
                    --comps;            // Successful merge decreases component count
            }
        }
    }
    return comps.load();
}
