#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/* Compute the matrix multiplication Y=AX.  A is a sparse MxK matrix in COO format,
   X is a sparse KxN matrix in COO format.  Y is a dense MxN matrix in row-major.
   The implementation preserves the exact semantics of the original code while
   providing significant speed improvements on a modern multi‑core system.  */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N) noexcept
{
    /* Create a hash table that maps each row of X (the K dimension) to a list
       of its non‑zero entries.  This allows us to access, in O(1), all
       X-elements that can be multiplied by a given A-element.           */
    std::vector<std::vector<COOElement>> x_by_row(K);
    for (const auto& e : X) {
        // Assume the input is well‑formed: 0 <= e.row < K
        x_by_row[e.row].push_back(e);
    }

    Y.assign(M * N, 0.0);

    /* Parallelise the outer loop over the non‑zero elements of A.  Each
       thread works on a disjoint set of rows, so there is no need for
       atomic operations on Y because each Y[position] is updated only
       by the thread that owns the corresponding A-element.           */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < A.size(); ++i) {
        const auto& a = A[i];
        // Skip invalid rows – the original code assumes valid indices.
        if (a.column >= K) continue;
        const auto& xvec = x_by_row[a.column];
        if (xvec.empty()) continue;

        double a_val = a.value;
        for (const auto& x : xvec) {
            // Y[row][col] = a_row * x_row in dense form
            Y[a.row * N + x.column] += a_val * x.value;
        }
    }
}
