// Fast O(N²) DFT implementation with OpenMP parallelisation
// and trig‑free per‑element calculation.
void dft(std::vector<double> const& x, std::vector<std::complex<double>> &output) {
    const std::size_t N = x.size();
    output.assign(N, std::complex<double>(0.0, 0.0));

    // Pre‑allocate trig tables for speed (optional but useful for larger N)
    const double two_pi_over_N = 2.0 * M_PI / static_cast<double>(N);

    // Parallel over output indices k
    #pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < N; ++k) {
        const double angle_k = two_pi_over_N * static_cast<double>(k);
        const std::complex<double> wk(std::cos(angle_k), -std::sin(angle_k)); // exp(-i*2πk/N)

        std::complex<double> sum(0.0, 0.0);
        std::complex<double> power(1.0, 0.0); // w_k^n, starting with n=0

        for (std::size_t n = 0; n < N; ++n) {
            sum += x[n] * power;
            power *= wk;   // Next twiddle factor
        }
        output[k] = sum;
    }
