    const std::size_t block = 128;             // chunk per thread

    #pragma omp parallel for schedule(static,block) collapse(1)
    for (std::size_t i = 0; i + vec_len <= n; i += vec_len) {
#if defined(__AVX2__)
        __m256d v = _mm256_loadu_pd(&x[i]);           // load 4 doubles
        __m256d zeros = _mm256_setzero_pd();
        v = _mm256_max_pd(v, zeros);
        _mm256_storeu_pd(&x[i], v);
#else
        __m128d v1 = _mm_loadu_pd(&x[i]);             // load first 2 doubles
        __m128d v2 = _mm_loadu_pd(&x[i+2]);           // load next 2 doubles
        __m128d zeros = _mm_setzero_pd();
        v1 = _mm_max_pd(v1, zeros);
        v2 = _mm_max_pd(v2, zeros);
        _mm_storeu_pd(&x[i], v1);
        _mm_storeu_pd(&x[i+2], v2);
#endif
    }

    /* Handle remaining elements that don't fit into a full vector */
    for (std::size_t i = (n / vec_len) * vec_len; i < n; ++i) {
        x[i] = (x[i] > 0.0) ? x[i] : 0.0;
    }
