/* Compute z = alpha*x + y where x and y are sparse vectors.
   z is updated in place.  The elements of x and y are assumed
   sorted by increasing index. */
inline void sparseAxpy(double alpha,
                       std::vector<Element> const& x,
                       std::vector<Element> const& y,
                       std::vector<double> &z)
{
    std::size_t xi = 0, yi = 0;
    const std::size_t nx = x.size();
    const std::size_t ny = y.size();

    while (xi < nx && yi < ny)
    {
        const std::size_t ix = x[xi].index;
        const std::size_t iy = y[yi].index;

        if (ix < iy) {
            z[ix] += alpha * x[xi].value;
            ++xi;
        } else if (ix > iy) {
            z[iy] += y[yi].value;
            ++yi;
        } else {          /* ix == iy */
            z[ix] += alpha * x[xi].value + y[yi].value;
            ++xi; ++yi;
        }
    }

    while (xi < nx) {
        z[x[xi].index] += alpha * x[xi].value;
        ++xi;
    }
    while (yi < ny) {
        z[y[yi].index] += y[yi].value;
        ++yi;
    }
}
