#pragma once
#include <vector>
#include <algorithm>
#include <limits>
#include <omp.h>

/*  Union–Find structure with path compression and union‑by‑size.
 *  All operations are thread safe because each element is updated
 *  only from its own thread (there is no race on a single element).
 *  The parallel for loop merges components independently.
 */
struct UnionFind {
    std::vector<int> parent;   // negative value means root and stores -size
    UnionFind(int n) : parent(n, -1) {}

    // find with path compression
    int find(int x) {
        int r = x;
        while (parent[r] >= 0) r = parent[r];
        while (x != r) {
            int p = parent[x];
            parent[x] = r;
            x = p;
        }
        return r;
    }

    // union by size, atomic for root updates
    void unite(int a, int b) {
        int ra = find(a);
        int rb = find(b);
        if (ra == rb) return;
        // ensure ra is the larger component
        if (parent[ra] > parent[rb]) std::swap(ra, rb);
        // merge smaller into larger atomically
        #pragma omp atomic capture
        int old = parent[ra];
        parent[ra] = old + parent[rb];
        parent[rb] = ra;
    }

    // returns the size of the component containing x
    int size(int x) const {
        int r = find(x);
        return -parent[r];
    }
};

/* Return the number of vertices in the largest component of the graph
 * defined by the adjacency matrix A.  A is an NxN adjacency matrix
 * stored in row‑major order.  The implementation uses a parallel Union‑Find
 * to achieve maximum speed on an 8‑thread machine.
 */
int largestComponent(std::vector<int> const& A, size_t N) {
    UnionFind uf(static_cast<int>(N));

    // only examine the upper triangle of the symmetric adjacency matrix
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        int base = i * static_cast<int>(N);
        for (int j = i + 1; j < static_cast<int>(N); ++j) {
            if (A[base + j] == 1)
                uf.unite(i, j);
        }
    }

    int maxSize = 0;
    for (int i = 0; i < static_cast<int>(N); ++i)
        maxSize = std::max(maxSize, uf.size(i));

    return maxSize;
}
