#pragma once
#include <numeric>
#include <vector>
#include <omp.h>

/* Compute the prefix sum of the vector x into output.
   Example:
   input:  [1, 7, 4, 6, 6, 2]
   output: [1, 8,12,18,24,26]
   The implementation uses a two‑step parallel algorithm:
   1. Each thread computes the inclusive scan of its assigned BLOCK.
   2. Thread 0 computes the prefix of per‑block totals, then each thread adds
      that offset to all its elements.
   This preserves the exact behavior while scaling across the available threads.
*/
void prefixSum(std::vector<int64_t> const& x, std::vector<int64_t> &output) {
    const std::size_t N = x.size();
    if (N != output.size())
        throw std::runtime_error("output vector must have the same size as x");

    if (N == 0) return;

    const int num_threads = omp_get_max_threads();
    const std::size_t block_size = (N + num_threads - 1) / num_threads;   // ceil

    std::vector<int64_t> block_totals(num_threads, 0);
    std::vector<int64_t> block_offsets(num_threads, 0);

    /* 1. Parallel inclusive scan over each block */
#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * block_size;
        const std::size_t end   = std::min(start + block_size, N);

        if (start < end) {
            int64_t acc = x[start];
            output[start] = acc;
            for (std::size_t i = start + 1; i < end; ++i) {
                acc += x[i];
                output[i] = acc;
            }
            block_totals[tid] = acc;        // sum of this block
        }
    }

    /* 2. Prefix sum of block_totals to get offsets for each block */
    block_offsets[0] = 0;
    for (int i = 1; i < num_threads; ++i)
        block_offsets[i] = block_offsets[i-1] + block_totals[i-1];

    /* 3. Add block offsets to each element in its block */
#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * block_size;
        const std::size_t end   = std::min(start + block_size, N);
        const int64_t offset = block_offsets[tid];

        if (start < end) {
            for (std::size_t i = start; i < end; ++i) {
                output[i] += offset;
            }
        }
    }
}
