/* Return the area of the smallest triangle that can be formed by any 3 points. */
double smallestArea(std::vector<Point> const& points)
{
    const std::size_t n = points.size();
    if (n < 3)
        return 0.0;

    /* use area * 2 (no 0.5) to avoid a division in every iteration */
    double min2Area = std::numeric_limits<double>::infinity();

    /* parallelise the search over the outer index. */
    #pragma omp parallel for schedule(static) reduction(min:min2Area)
    for (std::size_t i = 0; i < n - 2; ++i)
    {
        const Point& Ai = points[i];
        for (std::size_t j = i + 1; j < n - 1; ++j)
        {
            const Point& Bj = points[j];
            for (std::size_t k = j + 1; k < n; ++k)
            {
                const Point& Ck = points[k];
                /* twice the triangle area using the cross‑product formula */
                const double area2 =
                    std::abs(Ai.x * (Bj.y - Ck.y) +
                             Bj.x * (Ck.y - Ai.y) +
                             Ck.x * (Ai.y - Bj.y));
                if (area2 < min2Area)
                    min2Area = area2;
            }
        }
    }

    return 0.5 * min2Area;
}
