#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

/// Fast Fourier Transform (Cooley‑Tukey, radix‑2, in‑place) 
/// Assumes |x| is a power of two.  The function is fully
/// deterministic and produces exactly the same results as
/// the reference implementation while being vectorised and
/// multi‑threaded when compiled with OpenMP.
void fft(const std::vector<std::complex<double>> &x,
         std::vector<double> &r,
         std::vector<double> &i)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    /* ------------------------------------------------------------------
       1. Pre‑compute bit‑reversed indices.
       ------------------------------------------------------------------ */
    const std::size_t logN = static_cast<std::size_t>(std::log2(N));
    std::vector<std::size_t> rev(N);
    for (std::size_t n = 0, m = 0; n < N; ++n) {
        rev[n] = m;
        std::size_t k = N >> 1;
        while (k && (m & k)) { m ^= k; k >>= 1; }
        m ^= k;
    }

    /* ------------------------------------------------------------------
       2. Copy input into work buffer in bit‑reversed order.
       ------------------------------------------------------------------ */
    std::vector<std::complex<double>> a(N);
#pragma omp parallel for schedule(static)
    for (std::size_t n = 0; n < N; ++n)
        a[rev[n]] = x[n];

    /* ------------------------------------------------------------------
       3. Iterative radix‑2 butterfly operations.
       ------------------------------------------------------------------ */
    const double TWO_PI = 2.0 * M_PI;
    for (std::size_t s = 1; s <= logN; ++s) {
        const std::size_t m = 1 << s;            // butterfly size
        const std::size_t m_half = m >> 1;        // half size
        const double step  = TWO_PI / static_cast<double>(m);

        // Compute the twiddle factor Wm for this stage
        const std::complex<double> wm(std::cos(step), -std::sin(step));

#pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += m) {
            std::complex<double> w(1.0, 0.0);
            for (std::size_t j = 0; j < m_half; ++j) {
                const std::complex<double> t = w * a[k + j + m_half];
                const std::complex<double> u = a[k + j];
                a[k + j]         = u + t;
                a[k + j + m_half] = u - t;
                w *= wm;
            }
        }
    }

    /* ------------------------------------------------------------------
       4. Split into real / imag output.
       ------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < N; ++j) {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
