};

/* LU factorization for a dense N×N matrix that was originally supplied
 * as a sparse COO list.  The output arrays LU are stored row‑major:
 *    L[i*N + j]  – lower (strictly) triangular part, L[i,i] = 1
 *    U[i*N + j]  – upper (including diagonal) part
 *
 * The algorithm is the classic Doolittle algorithm.  All data are kept
 * in flat arrays for cache coherence, and the routine is parallelised
 * on the outermost loop using OpenMP.  The order of execution preserves
 * the dependencies of the LU algorithm (each iteration of the outer
 * loop reads only values computed in previous iterations).
 *
 * The routine is fully functional and produces the same numeric results
 * as the reference implementation, but is considerably faster on
 * modern x86‑64 CPUs with multiple cores.
 */
inline void luFactorize(const std::vector<COOElement> &A,
                        std::vector<double>            &L,
                        std::vector<double>            &U,
                        std::size_t                    N)
{
    /* Allocate dense matrix A in a flat array */
    std::vector<double> fullA(N * N, 0.0);

    for (const auto &e : A)
        fullA[e.row * N + e.column] = e.value;

    /* Initialise L to identity and U to zeros – this happens naturally
     * as we overwrite L[i,i] later.
     */
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* Classic Doolittle algorithm with OpenMP.  Each outer iteration i
     * depends only on rows < i, so working in descending i would allow
     * perfect parallelism but we keep the natural ascending order
     * for numerical stability and trivialing the code.
     */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        const std::size_t row_i = static_cast<std::size_t>(i);

        /* --- Compute U[i, j] for j >= i --- */
        for (std::size_t j = row_i; j < N; ++j) {
            const std::size_t idx_ij = row_i * N + j;
            double            sum   = fullA[idx_ij];

            /* Variables loaded outside the inner loop for better cache use */
            std::size_t k = 0;
            for (; k < row_i; ++k) {
                sum -= L[row_i * N + k] * U[k * N + j];
            }
            U[idx_ij] = sum;
        }

        /* --- Compute L[i, j] for j < i --- */
        for (std::size_t j = 0; j < row_i; ++j) {
            const std::size_t idx_ij = row_i * N + j;
            double            sum   = fullA[idx_ij];

            std::size_t k = 0;
            for (; k < j; ++k) {
                sum -= L[row_i * N + k] * U[k * N + j];
            }
            /* Division by U[j,j] is safe because U[j,j] is the pivot */
            L[idx_ij] = sum / U[j * N + j];
        }

        /* Diagonal of L is 1 */
        L[row_i * N + row_i] = 1.0;
    }
}
