/* Compute one iteration of a 3‑point 1‑D Jacobi stencil.
   -------------------------------------------------------------------------------------------------
   * Parameters
   *   input  – const reference to the input array
   *   output – reference to the array that will receive the results
   *
   * The function performs the exact same computation as the reference implementation:
   *   output[i] = (input[i‑1] + input[i] + input[i+1]) / 3
   *
   * Boundary elements are handled as: input[-1] and input[N] are treated as 0.
   *
   * The implementation below preserves the semantics while optimizing for:
   *   • Parallel execution over 8 logical threads (OpenMP Parallel For)
   *   • Efficient memory access by using raw pointers
   *   • Avoiding branch imbalance with explicit boundary handling
   *   • Using a pre‑computed constant divisor.
   */
inline void jacobi1D(const std::vector<double> &input, std::vector<double> &output)
{
    const std::size_t N = input.size();
    if (N == 0) return;

    const double inv3 = 1.0 / 3.0;

    const double *in = input.data();
    double *out = output.data();

    /* Parallel loop – static chunking works well on a shared‑memory machine with a small
       number of homogeneous cores. The work per iteration is tiny, so we give each
       thread a sizeable chunk (1K elements) to reduce scheduling overhead. */
#pragma omp parallel for schedule(static, 1024) if (N > 1024)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(N); ++i)
    {
        double sum = in[i];
        if (i > 0)   sum += in[i - 1];
        if (i + 1 < static_cast<std::ptrdiff_t>(N)) sum += in[i + 1];
        out[i] = sum * inv3;
    }
}
