/* Replace the i-th element of the vector x with the minimum value from indices 0 through i.
   Examples:
   input: [8, 6, -1, 7, 3, 4, 4]
   output: [8, 6, -1, -1, -1, -1, -1]
   input: [5, 4, 6, 4, 3, 6, 1, 1]
   output: [5, 4, 4, 4, 3, 3, 1, 1]
*/
inline void partialMinimums(std::vector<float> &x)
{
    const std::size_t n = x.size();
    if (n == 0)
        return;

    /* Choose a block size a little larger than a cache line.
       This keeps the per‑block work independent and well balanced across threads.
       The exact size is not critical; the algorithm works for any block size. */
    const std::size_t block_size = 256;

    const std::size_t num_blocks = (n + block_size - 1) / block_size;

    /* First pass: each block computes its local minimum and writes it to a
       separate vector. */
    std::vector<float> local_min(num_blocks);
#pragma omp parallel for schedule(static)
    for (std::size_t b = 0; b < num_blocks; ++b)
    {
        const std::size_t start = b * block_size;
        const std::size_t end   = std::min(start + block_size, n);
        float m = std::numeric_limits<float>::max();
        for (std::size_t i = start; i < end; ++i)
            m = std::min(m, x[i]);
        local_min[b] = m;
    }

    /* Prefix sum (inclusive) of the block minima. */
    std::vector<float> block_prefix(num_blocks);
    if (!local_min.empty())
    {
        block_prefix[0] = local_min[0];
        for (std::size_t b = 1; b < num_blocks; ++b)
            block_prefix[b] = std::min(block_prefix[b - 1], local_min[b]);
    }

    /* Second pass: each element takes the minimum of its own block’s prefix
       minimum and any earlier elements in the same block.  The per‑block
       prefix values are already correct for all elements, so we only need
       the per‑block scan. */
#pragma omp parallel for schedule(static)
    for (std::size_t b = 0; b < num_blocks; ++b)
    {
        const std::size_t start = b * block_size;
        const std::size_t end   = std::min(start + block_size, n);
        float cur = block_prefix[b];
        for (std::size_t i = start; i < end; ++i)
        {
            if (x[i] < cur)
                cur = x[i];
            x[i] = cur;
        }
    }
}
