                                          { -1,  8, -1 },
                                          { -1, -1, -1 } };

/* Convolve the edge kernel with a grayscale image.
 *   imageIn  – input image stored row‑major (size N×N)
 *   imageOut – output image (pre‑allocated to N×N)
 *   N        – image dimension
 *
 * The implementation is fully parallelised with OpenMP, eliminates
 * redundant boundary checks, and performs clipping in a single
 * comparison chain for maximum CPU speed.
 */
inline void convolveKernel(const std::vector<int> &imageIn,
                           std::vector<int>       &imageOut,
                           const size_t          N)
{
    const int *src = imageIn.data();
    int       *dst = imageOut.data();
    const size_t stride = N;          // row stride

    /* Parallelise over rows; inner loop is already cache‑friendly. */
    #pragma omp parallel for schedule(static, 128)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        const int baseIdx = i * stride;
        for (int j = 0; j < static_cast<int>(N); ++j) {
            int sum = 0;

            /* Unrolled 3×3 loop – fewer branches and better vectorisation. */
            for (int di = -1; di <= 1; ++di) {
                int ni = i + di;
                if (ni < 0 || ni >= static_cast<int>(N)) continue;
                const int rowOffset = ni * stride;
                for (int dj = -1; dj <= 1; ++dj) {
                    int nj = j + dj;
                    if (nj < 0 || nj >= static_cast<int>(N)) continue;
                    sum += src[rowOffset + nj] * edgeKernel[di + 1][dj + 1];
                }
            }

            /* Clip result to [0,255] – a single branch is sufficient. */
            dst[baseIdx + j] = static_cast<int>(std::min<std::max<int>(sum, 0), 255));
        }
    }
}
