/*
   For each cell in an N×N grid, set output[i][j] to 1 if and only if
   exactly one of its 4‑direct neighbors (north, south, west, east)
   contains a 1 in the input grid. No other cells are considered.
   The input and output are stored in row‑major order.

   The implementation below preserves bit‑exact semantics of the
   original code while exploiting:
   • Data locality by using pointer arithmetic.
   • Parallel execution of the outer row loop via OpenMP.
   • A small micro‑optimisation: the neighbour counts are kept in a
     short integer (16‑bit) because the maximum possible count is 4.
*/

inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int> &output,
                     size_t N) noexcept {

    // Work on raw pointers for maximal speed.
    const int* in  = input.data();
    int*       out = output.data();
    const size_t stride = N;          // number of ints per row

#if defined(_OPENMP)
    // Parallelise rows. Each thread works on a distinct range of rows.
    #pragma omp parallel for schedule(static)
#endif
    for (int i = 0; i < static_cast<int>(N); ++i) {
        for (int j = 0; j < static_cast<int>(N); ++j) {

            // Accumulate neighbour count in a 16‑bit integer.
            short count = 0;

            // North
            if (i > 0 && in[(i-1)*stride + j] == 1) ++count;
            // South
            if (i < static_cast<int>(N)-1 && in[(i+1)*stride + j] == 1) ++count;
            // West
            if (j > 0 && in[i*stride + j-1] == 1) ++count;
            // East
            if (j < static_cast<int>(N)-1 && in[i*stride + j+1] == 1) ++count;

            // Write the result using the original Bool‑to‑int convention.
            out[i*stride + j] = count == 1 ? 1 : 0;
        }
    }
