#pragma once
#include <vector>
#include <algorithm>
#include <numeric>
#include <omp.h>

struct Point {
    double x, y;
};

// Faster comparison functor
struct PointCmp {
    bool operator()(Point const& a, Point const& b) const {
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    }
};

// Inline cross‑product
inline double cross(const Point& a, const Point& b, const Point& c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/* Find the convex hull of a set of points.  The hull points are returned in
 * counter‑clockwise order starting from the point with the smallest
 * (x, y), excluding the last point which would duplicate the first one.
 */
void convexHull(std::vector<Point> const& points, std::vector<Point> &hull) {
    // Trivial cases
    size_t n = points.size();
    if (n < 3) {
        hull = points;
        return;
    }

    // Copy + sort -- std::sort is already parallel‑aware on many GCC
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(), PointCmp{});

    // Pre‑allocate result buffer (worst case 2*n)
    std::vector<Point> res;
    res.resize(2 * n);
    size_t k = 0;

    // Build the lower hull
    for (size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(res[k-2], res[k-1], pts[i]) <= 0.0) --k;
        res[k++] = pts[i];
    }

    // Build the upper hull
    size_t t = k + 1;               // starting index for upper part
    for (size_t i = n; i-- > 1;) {  // i goes n-1 .. 1
        while (k >= t && cross(res[k-2], res[k-1], pts[i-1]) <= 0.0) --k;
        res[k++] = pts[i-1];
    }

    // Trim to actual hull size (exclude the repeated first point)
    res.resize(k-1);
    hull.swap(res);   // move without copy
}
