inline void luFactorize(std::vector<double> &A, size_t N)
{
    // work on raw pointer for speed
    double *const a = A.data();

    // Loop over pivot column; serial to respect data dependencies
    for (size_t k = 0; k < N; ++k)
    {
        const double pivot = a[k * N + k];
        const size_t kp = k * N;                 // row offset of k

        // Update rows below pivot in parallel
        #pragma omp parallel for schedule(static)
        for (size_t i = k + 1; i < N; ++i)
        {
            const size_t ip = i * N;
            const double factor = a[ip + k] / pivot;
            a[ip + k] = factor;                   // store L element

            // Vectorised update of the remaining row
            double* restrict row_i   = a + ip + k + 1;
            const double* restrict row_k = a + kp + k + 1;
            const size_t len = N - k - 1;
            size_t j = 0;
            // SIMD loop: unroll by 4 for AVX2
            for (; j + 3 < len; j += 4)
            {
                row_i[j]   -= factor * row_k[j];
                row_i[j+1] -= factor * row_k[j+1];
                row_i[j+2] -= factor * row_k[j+2];
                row_i[j+3] -= factor * row_k[j+3];
            }
            // tail
            for (; j < len; ++j)
                row_i[j] -= factor * row_k[j];
        }
    }
}
