static inline uint32_t reverse_bits(const uint32_t v, const unsigned int bits) {
    uint32_t b = v;
    b = (((b & 0xaaaaaaaau) >> 1) | ((b & 0x55555555u) << 1));
    b = (((b & 0xccccccccu) >> 2) | ((b & 0x33333333u) << 2));
    b = (((b & 0x0f0f0f0fu) >> 4) | ((b & 0xf0f0f0f0u) << 4));
    b = (((b & 0x00ff00ffu) >> 8) | ((b & 0xff00ff00u) << 8));
    b = ((b >> 16) | (b << 16)) >> (32 - bits);
    return b;
}

inline void fftConjugate(std::vector<std::complex<double>>& x) {
    const size_t N = x.size();
    if (N <= 1) return;

    const unsigned int logN = static_cast<unsigned int>(std::log2(N));

    /* Bit‑reversal permutation – parallelized */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const uint32_t rev = reverse_bits(static_cast<uint32_t>(i), logN);
        if (rev > i) std::swap(x[i], x[rev]);
    }

    /* Pre‑compute twiddle‑factor roots of unity */
    std::vector<std::complex<double>> roots(N / 2);
    const double two_pi = 2.0 * M_PI;
    for (size_t k = 0; k < N / 2; ++k)
        roots[k] = std::polar(1.0, -two_pi * k / static_cast<double>(N));

    /* Radix‑2 Cooley‑Tukey FFT – logN stages */
    for (unsigned int stage = 0; stage < logN; ++stage) {
        const size_t stride = 1ULL << stage;
        const size_t step   = stride << 1;
        const size_t twiddle_stride = N / step;

        /* Parallel butterfly in each stage */
        #pragma omp parallel for schedule(static)
        for (size_t block = 0; block < N; block += step) {
            for (size_t i = 0; i < stride; ++i) {
                const size_t even = block + i;
                const size_t odd  = even + stride;
                const std::complex<double> t = roots[i * twiddle_stride] * x[odd];
                x[odd] = x[even] - t;
                x[even] += t;
            }
        }
    }

    /* Conjugate the result */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}
