#include <omp.h>   // OpenMP header

struct Point {
    double x, y;
};

/* Squared distance – used internally for efficiency */
inline double sqdist(Point const& a, Point const& b) {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx*dx + dy*dy;
}

/* Compute the perimeter of the convex hull of the given points.
   The implementation is a lightweight, cache‑friendly version of
   Andrew's monotone‑chain algorithm with a parallel accumulation
   of the edge lengths. */
double convexHullPerimeter(std::vector<Point> const& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    /* Sort points by x, then y */
    std::vector<Point> pts = points;
    pts.resize(n);
    std::sort(pts.begin(), pts.end(), [](const Point& a, const Point& b) {
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    });

    /* Monotone chain construction */
    std::vector<Point> hull(2*n);          // maximum possible size
    std::size_t k = 0;                     // current hull size

    auto cross = [](const Point& a, const Point& b, const Point& c) {
        return (b.x - a.x)*(c.y - a.y) - (b.y - a.y)*(c.x - a.x);
    };

    /* Lower hull */
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(hull[k-2], hull[k-1], pts[i]) <= 0.0) k--;
        hull[k++] = pts[i];
    }

    /* Upper hull */
    std::size_t t = k + 1;                 // start point of upper hull
    for (std::size_t i = n-1; i-- > 0; ) {
        while (k >= t && cross(hull[k-2], hull[k-1], pts[i]) <= 0.0) k--;
        hull[k++] = pts[i];
    }

    hull.resize(k-1);                      // remove duplicate of first point

    /* Parallel accumulation of perimeter */
    double peri = 0.0;
    const std::size_t m = hull.size();
#pragma omp parallel for reduction(+:peri) default(none) shared(hull,m)
    for (std::size_t i = 0; i < m; ++i) {
        const std::size_t j = (i+1)%m;
        peri += std::sqrt(sqdist(hull[i], hull[j]));
    }
    return peri;
}
