// Helper to compute neighbor sum with SIMD lanes
inline __m128i load3(const int* a, const int* b, const int* c)
{
    // Load three consecutive ints from a,b,c and return packed sum
    __m128i va = _mm_cvtsi32_si128(*a);
    __m128i vb = _mm_cvtsi32_si128(*b);
    __m128i vc = _mm_cvtsi32_si128(*c);
    __m128i v = _mm_add_epi32(va, vb);
    v           = _mm_add_epi32(v, vc);
    return v;
}

// Main routine
void gameOfLife(std::vector<int> const& input, std::vector<int> &output, size_t N)
{
    // Ensure output has the right size
    if (output.size() != N * N)
        output.resize(N * N);

    // Precompute pointers for faster indexing
    const int *in = input.data();
    int *out = output.data();

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        size_t idx = i * N;
        for (size_t j = 0; j < N; ++j, ++idx)
        {
            int sum = 0;
            // Compute neighbor sum with bounds checks
            if (i > 0)                 sum += in[(i-1)*N + j];
            if (i + 1 < N)             sum += in[(i+1)*N + j];
            if (j > 0)                 sum += in[i*N + (j-1)];
            if (j + 1 < N)             sum += in[i*N + (j+1)];
            if (i > 0 && j > 0)        sum += in[(i-1)*N + (j-1)];
            if (i > 0 && j + 1 < N)    sum += in[(i-1)*N + (j+1)];
            if (i + 1 < N && j > 0)    sum += in[(i+1)*N + (j-1)];
            if (i + 1 < N && j + 1 < N) sum += in[(i+1)*N + (j+1)];

            // Apply rules
            int cur = in[idx];
            if (cur)
            {
                out[idx] = (sum == 2 || sum == 3) ? 1 : 0;
            }
            else
            {
                out[idx] = (sum == 3) ? 1 : 0;
            }
        }
    }
}
