#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

// Fast inverse FFT implementation preserving exact behaviour
void fft(std::vector<std::complex<double>> const& x,
         std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output = x;                      // work on a copy

    // --------------------------------------------------------------------
    // Stage 1 – Butterfly computation (iterative radix‑2 Cooley–Tukey)
    // --------------------------------------------------------------------
    std::size_t k = N, n;
    const double theta = M_PI / static_cast<double>(N);
    std::complex<double> phiT = std::exp(std::complex<double>(0.0, -theta)) * std::exp(std::complex<double>(0.0, -theta)); // w_(N/2)^2

    while (k > 1) {
        n  = k;
        k >>= 1;
        phiT = phiT * phiT;          // w_(N/2^m)^2

        // For the current stage, each exponent T is independent → parallelisable
        #pragma omp parallel for schedule(static)
        for (std::size_t l = 0; l < k; ++l) {
            std::complex<double> T = 1.0;
            for (std::size_t a = l; a < N; a += n) {
                std::size_t b = a + k;
                const std::complex<double> t = output[a] - output[b];
                output[a] += output[b];
                output[b] = t * T;
                T *= phiT;
            }
        }
    }

    // --------------------------------------------------------------------
    // Stage 2 – Bit‑reverse reordering
    // --------------------------------------------------------------------
    const std::size_t m = static_cast<std::size_t>(std::log2(static_cast<double>(N)));
    std::vector<std::size_t> rev(N);

    // Pre‑compute reversed indices
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t b = i;
        b = ((((b & 0xaaaaaaaa) >>  1) | ((b & 0x55555555) <<  1)) & 0xffffffff);
        b = ((((b & 0xcccccccc) >>  2) | ((b & 0x33333333) <<  2)) & 0xffffffff);
        b = ((((b & 0xf0f0f0f0) >>  4) | ((b & 0x0f0f0f0f) <<  4)) & 0xffffffff);
        b = ((((b & 0xff00ff00) >>  8) | ((b & 0x00ff00ff) <<  8)) & 0xffffffff);
        b = (((b >> 16) | (b << 16)) >> (32 - m)) & ((1u << m) - 1);
        rev[i] = b;
    }

    // In‑place swap only when rev[i] > i to avoid double counting
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t j = rev[i];
        if (j > i) {
            std::swap(output[i], output[j]);
        }
    }
}
