#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Example:
   input: A=[[1,4,2],[1,2,3],[2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
inline void solveLinearSystem(const std::vector<double> &A,
                              const std::vector<double> &b,
                              std::vector<double> &x,
                              const size_t N)
{
    // Work on copies because A and b are const
    std::vector<double> A_copy = A;
    std::vector<double> b_copy = b;

    // Gaussian elimination with OpenMP parallelization
    for (size_t i = 0; i + 1 < N; ++i)
    {
        const double pivot = A_copy[i * N + i];
        if (pivot == 0.0)            // singular matrix – give up
            return;

        const double inv_pivot = 1.0 / pivot;

#pragma omp parallel for schedule(static)
        for (size_t j = i + 1; j < N; ++j)
        {
            const double factor = A_copy[j * N + i] * inv_pivot;
            if (factor == 0.0) continue;

            double *row_j = &A_copy[j * N];
            const double *row_i = &A_copy[i * N];
            for (size_t k = i, end = N; k < end; ++k)
                row_j[k] -= factor * row_i[k];

            b_copy[j] -= factor * b_copy[i];
        }
    }

    // Back substitution – single threaded (data dependencies)
    for (int i = static_cast<int>(N) - 1; i >= 0; --i)
    {
        const double *row = &A_copy[i * N];
        double sum = 0.0;
        for (size_t j = i + 1; j < N; ++j)
            sum += row[j] * x[j];
        x[i] = (b_copy[i] - sum) / row[i];
    }
}
