#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <cstdint>
#include <omp.h>

#if !defined(M_PI)
# define M_PI 3.14159265358979323846
#endif

// -----------------------------------------------------------------------
// Iterative Cooley–Tukey radix‑2 FFT (in place).  The routine works
// for any power‑of‑two length N.  It is thread–safe because every
// iteration writes to disjoint memory locations.  We use OpenMP to
// parallelise the butterfly stage loops.
//
// The algorithm follows the standard iterative FFT scheme used in
// practice: 1) bit‑reversal reordering, 2) log₂(N) stages of
// butterflies in which the twiddle factors are pre‑computed on
// demand.  All arithmetic is performed in double precision (the
// standard).
// -----------------------------------------------------------------------

inline void bit_reverse_inplace(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    std::size_t j = 0;
    for (std::size_t i = 1; i < N; ++i)
    {
        std::size_t bit = N >> 1;
        while (j & bit)
        {
            j ^= bit;
            bit >>= 1;
        }
        j ^= bit;

        if (i < j)
        {
            std::swap(x[i], x[j]);
        }
    }
}

inline void fft(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    // re‑order the input array in bit‑reversed order
    bit_reverse_inplace(x);

    // main FFT loop
    for (std::size_t s = 1; s <= static_cast<std::size_t>(std::log2(N)); ++s)
    {
        const std::size_t m  = 1ULL << s;
        const std::size_t m2 = m >> 1;
        const double      theta = -2.0 * M_PI / static_cast<double>(m);
        const std::complex<double> w_m(std::cos(theta), std::sin(theta));

        // process each butterfly group in parallel
        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += m)
        {
            std::complex<double> w = 1.0;
            for (std::size_t j = 0; j < m2; ++j)
            {
                std::complex<double> t = w * x[k + j + m2];
                x[k + j + m2] = x[k + j] - t;
                x[k + j]      += t;
                w *= w_m;
            }
        }
    }
}

// -----------------------------------------------------------------------
// Inverse FFT.  The routine follows the textbook definition: conjugate,
// forward FFT, conjugate again, normalise by 1/N.
// -----------------------------------------------------------------------
inline void ifft(std::vector<std::complex<double>>& x)
{
    // conjugate
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i)
        x[i] = std::conj(x[i]);

    // forward transform
    fft(x);

    // conjugate again
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i)
        x[i] = std::conj(x[i]);

    // Normalisation
    const double invN = 1.0 / static_cast<double>(x.size());
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i)
        x[i] *= invN;
}
