// Find the index of the element that is closest to PI.
// The function keeps the original behaviour: on ties, the first
// (smallest index) element is returned.
size_t findClosestToPi(const std::vector<double>& x) {
    const size_t n = x.size();
    // Handle the degenerate empty case (behaviour unspecified in the original
    // code, but we guard against UB).
    if (n == 0) return 0;

    const double* data = x.data();

    // Shared variables that will be updated atomically.
    double global_min = DBL_MAX;
    size_t  global_idx = 0;

#pragma omp parallel
    {
        double local_min  = DBL_MAX;
        size_t  local_idx = 0;
        bool    local_set = false;

#pragma omp for nowait
        for (size_t i = 0; i < n; ++i) {
            const double diff = std::fabs(data[i] - M_PI);
            if (!local_set || diff < local_min ||
                (diff == local_min && i < local_idx)) {
                local_min = diff;
                local_idx = i;
                local_set = true;
            }
        }

        // Combine the local minima into the global result.
#pragma omp critical
        {
            if (!local_set) return;  // nothing to do
            if (local_min < global_min ||
                (local_min == global_min && local_idx < global_idx)) {
                global_min = local_min;
                global_idx = local_idx;
            }
        }
    }

    return global_idx;
}
