#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * High‑performance GEMM using cache blocking and OpenMP.
 *
 *   C += A * B
 *
 *   A : M × K (row‑major)
 *   B : K × N (row‑major)
 *   C : M × N (row‑major)
 *
 * The function preserves the exact semantics of the reference
 * implementation – it simply adds the product into the existing
 * contents of C. The code is fully parallelisable using
 * OpenMP's parallel for and is tuned for cache friendliness:
 *
 *   1. The outer two loops (i, j) are blocked to keep the active
 *      working set small (approximately 64 KiB or the L2 cache).
 *   2. The innermost accumulation loop runs over k.
 *   3. Data is accessed in a cache‑friendly order: C and B
 *      are streamed sequentially on the inner loops.
 */

inline void gemm(std::vector<double> const &A,
                 std::vector<double> const &B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    /* Choose a block size that reasonably fits in L2/L3 cache. */
    constexpr size_t BLOCK = 64;                 // 64×64 = 4 KiB per block (per matrix)
    const size_t  blockM = BLOCK;
    const size_t  blockN = BLOCK;
    const size_t  blockK = BLOCK;

    /* Parallelise the outermost i‑loop. */
    #pragma omp parallel for schedule(static)
    for (size_t i0 = 0; i0 < M; i0 += blockM) {
        size_t i_max = std::min(i0 + blockM, M);
        for (size_t j0 = 0; j0 < N; j0 += blockN) {
            size_t j_max = std::min(j0 + blockN, N);
            for (size_t k0 = 0; k0 < K; k0 += blockK) {
                size_t k_max = std::min(k0 + blockK, K);

                /* Unroll inner loops for a modest speed win. */
                for (size_t i = i0; i < i_max; ++i) {
                    double *Ci = &C[i * N + j0];
                    const double *Ai = &A[i * K + k0];
                    for (size_t j = j0; j < j_max; ++j, ++Ci, ++Ai) {
                        double a_val = *Ai;
                        if (a_val == 0.0) continue;           // skip zeros
                        const double *Bj = &B[(k0 + (k_max - k0)) * N + j];
                        // accumulate over k inside the innermost loop
                        for (size_t k = k0; k < k_max; ++k, ++Bj) {
                            *Ci += a_val * B[k * N + j];
                        }
                    }
                }
            }
        }
    }
}
