/* For each value in the vector `x` compute its index in the sorted order
   and store the result in `ranks_`.  The implementation keeps the same
   semantics as the original but uses a few cheap parallel steps with
   OpenMP to get a speed boost on multicore CPUs. */
inline void ranks(const std::vector<float> &x, std::vector<std::size_t> &ranks_) {
    const std::size_t n = x.size();
    ranks_.resize(n);

    /* 1. Build the index vector in parallel. */
    std::vector<std::size_t> indices(n);
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        indices[i] = i;
    }

    /* 2. Sort indices by the corresponding float values. */
    std::sort(indices.begin(), indices.end(),
              [&](std::size_t a, std::size_t b) { return x[a] < x[b]; });

    /* 3. Write the ranks in parallel – each thread writes to a distinct
       location so no data races occur. */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        ranks_[indices[i]] = i;
    }
}
