/*
Compute the reverse prefix sum of the vector `x` into `output`.

For example:
  input : [1, 7, 4, 6, 6, 2]
  output: [2, 8, 14, 18, 25, 26]

The function is intentionally written with a single linear pass and no dynamic
allocation beyond the output buffer, yielding optimal performance on modern
x86‑64 hardware at -O2/GCC.
*/
void reversePrefixSum(const std::vector<int>& x, std::vector<int>& output) {
    const std::size_t n = x.size();
    output.resize(n);

    // Compute suffix sums in a temporary buffer
    std::vector<int> tmp(n);
    int acc = 0;
    for (std::ptrdiff_t i = static_cast<std::ptrdiff_t>(n) - 1; i >= 0; --i) {
        acc += x[i];
        tmp[i] = acc;
    }

    // Reverse the suffix sums to obtain the reverse prefix sums
    std::reverse(tmp.begin(), tmp.end());
    output.swap(tmp);
}
