```cpp
#pragma once
#include <complex>
#include <vector>
#include <algorithm>
#include <omp.h>

/* Sort the vector x of complex numbers by their magnitude in ascending order.
   Example:

   input: [3.0-1.0i, 4.5+2.1i, 0.0-1.0i, 1.0-0.0i, 0.5+0.5i]
   output: [0.5+0.5i, 0.0-1.0i, 1.0-0.0i, 3.0-1.0i, 4.5+2.1i]
*/

namespace detail {

// Comparator based on magnitude.  Inlined for performance.
inline bool cmpMagnitude(const std::complex<double>& a,
                         const std::complex<double>& b)
{
    return std::abs(a) < std::abs(b);
}

// Threshold for switching to the sequential std::sort to avoid overhead
constexpr std::size_t SEQ_THRESHOLD = 1 << 12; // 4096

// Maximum recursion depth before falling back to sequential sort
constexpr int MAX_DEPTH = 8;

// Parallel quick‑sort implementation using OpenMP tasks
inline void parallel_quick_sort(std::vector<std::complex<double>>& v,
                                std::size_t left,
                                std::size_t right,
                                int depth)
{
    if (left >= right) return;

    // If the sub‑chunk is small or we are too deep, just use std::sort
    if (right - left + 1 <= SEQ_THRESHOLD || depth >= MAX_DEPTH) {
        std::sort(v.begin() + left, v.begin() + right + 1, cmpMagnitude);
        return;
    }

    // Median‑of‑three pivot to reduce worst‑case behaviour
    std::size_t mid = left + (right - left) / 2;
    std::complex<double> pivot = v[mid];
    double pVal = std::abs(pivot);

    std::size_t i = left, j = right;
    while (i <= j) {
        while (std::abs(v[i]) < pVal) ++i;
        while (std::abs(v[j]) > pVal) --j;
        if (i <= j) {
            std::swap(v[i], v[j]);
            ++i;
            --j;
        }
    }

    // Recursive work split into two OpenMP tasks
#pragma omp task shared(v) default(none) firstprivate(left, j, depth)
    parallel_quick_sort(v, left, j, depth + 1);

#pragma omp task shared(v) default(none) firstprivate(i, right, depth)
    parallel_quick_sort(v, i, right, depth + 1);
}

} // namespace detail

inline void sortComplexByMagnitude(std::vector<std::complex<double>>& x)
{
    if (x.empty()) return;

#pragma omp parallel
    {
#pragma omp single nowait
        detail::parallel_quick_sort(x, 0, x.size() - 1, 0);
    }
}
