#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Optimised 5‑point 2‑D Jacobi stencil
 *
 *   output[i,j] = (input[i,j] + input[i-1,j] + input[i+1,j] +
 *                  input[i,j-1] + input[i,j+1]) / 5.0
 *
 * The implementation:
 *   • Uses OpenMP parallel for with a static schedule to supply the
 *     8 available threads.
 *   • Applies a 32‑element cache blocking on the outer loop to keep
 *     the active sub‑chunk in L1/L2 cache.
 *   • Employs SIMD explicit intrinsics (AVX‑512 if available,
 *     otherwise AVX) to vectorise the inner horizontal accumulation.
 *   • Avoids branch mispredictions by un‑rolling the boundary cases
 *     into separate loops.
 *
 *   The algorithm is mathematically identical to the reference
 *   implementation but should deliver a significant speedup on
 *   modern x86‑64 hardware.
 */

inline void stencil_row_5_avx(double const *restrict src_row,
                              double const *restrict src_above,
                              double const *restrict src_below,
                              double *restrict dst_row,
                              size_t N)
{
#if defined(__AVX512F__)
    constexpr double div5 = 1.0 / 5.0;
    const size_t simd_width = 8;                       // 512‑bit / 64‑bit
    size_t j = 0;
    for (; j + simd_width <= N; j += simd_width) {
        __m512d v0 = _mm512_loadu_pd(src_row + j - 1);   // left
        __m512d v1 = _mm512_loadu_pd(src_row + j);     // centre
        __m512d v2 = _mm512_loadu_pd(src_row + j + 1); // right
        __m512d v3 = _mm512_loadu_pd(src_above + j);   // north
        __m512d v4 = _mm512_loadu_pd(src_below + j);   // south
        __m512d v  = _mm512_add_pd(_mm512_add_pd(v0, v1),
                                   _mm512_add_pd(v2, _mm512_add_pd(v3, v4)));
        v = _mm512_mul_pd(v, _mm512_set1_pd(div5));
        _mm512_storeu_pd(dst_row + j, v);
    }
    for (; j < N; ++j) {
        double sum = src_row[j] + src_above[j] + src_below[j];
        if (j > 0) sum += src_row[j - 1];
        if (j < N - 1) sum += src_row[j + 1];
        dst_row[j] = sum * div5;
    }
#elif defined(__AVX__)
    constexpr double div5 = 1.0 / 5.0;
    const size_t simd_width = 4;                       // 256‑bit / 64‑bit
    size_t j = 0;
    for (; j + simd_width <= N; j += simd_width) {
        __m256d v0 = _mm256_loadu_pd(src_row + j - 1);   // left
        __m256d v1 = _mm256_loadu_pd(src_row + j);     // centre
        __m256d v2 = _mm256_loadu_pd(src_row + j + 1); // right
        __m256d v3 = _mm256_loadu_pd(src_above + j);   // north
        __m256d v4 = _mm256_loadu_pd(src_below + j);   // south
        __m256d v  = _mm256_add_pd(_mm256_add_pd(v0, v1),
                                   _mm256_add_pd(v2, _mm256_add_pd(v3, v4)));
        v = _mm256_mul_pd(v, _mm256_set1_pd(div5));
        _mm256_storeu_pd(dst_row + j, v);
    }
    for (; j < N; ++j) {
        double sum = src_row[j] + src_above[j] + src_below[j];
        if (j > 0) sum += src_row[j - 1];
        if (j < N - 1) sum += src_row[j + 1];
        dst_row[j] = sum * div5;
    }
#else
    // Fallback to scalar if vector intrinsics are not available
    constexpr double div5 = 1.0 / 5.0;
    for (size_t j = 0; j < N; ++j) {
        double sum = src_row[j] + src_above[j] + src_below[j];
        if (j > 0) sum += src_row[j - 1];
        if (j < N - 1) sum += src_row[j + 1];
        dst_row[j] = sum * div5;
    }
#endif
}

inline void jacobi2D_impl(const std::vector<double> &input,
                          std::vector<double> &output,
                          size_t N)
{
    const size_t block = 32;  // block size tuned for L1/L2 cache

    // Parallelise over outer blocks
    #pragma omp parallel for schedule(static)
    for (size_t i0 = 0; i0 < N; i0 += block) {
        const size_t i1 = std::min(i0 + block, N);

        for (size_t i = i0; i < i1; ++i) {
            const double *const src_row   = input.data() + i * N;
            const double *const src_above = (i > 0)   ? input.data() + (i - 1) * N : nullptr;
            const double *const src_below = (i + 1 < N) ? input.data() + (i + 1) * N : nullptr;
            double *const dst_row = output.data() + i * N;

            if (!src_above) { // i == 0
                // North edge: src_above is replaced with zero vector
                // We'll handle the first row separately
                for (size_t j = 0; j < N; ++j) {
                    double sum = src_row[j] + src_below[j];
                    if (j > 0) sum += src_row[j - 1];
                    if (j < N - 1) sum += src_row[j + 1];
                    dst_row[j] = sum / 5.0;
                }
            } else if (!src_below) { // i == N-1
                for (size_t j = 0; j < N; ++j) {
                    double sum = src_row[j] + src_above[j];
                    if (j > 0) sum += src_row[j - 1];
                    if (j < N - 1) sum += src_row[j + 1];
                    dst_row[j] = sum / 5.0;
                }
            } else {
                stencil_row_5_avx(src_row, src_above, src_below, dst_row, N);
            }
        }
    }
}

/* Public API (unchanged) */
inline void jacobi2D(const std::vector<double> &input,
                     std::vector<double> &output,
                     size_t N)
{
    // Ensure output buffer is sized correctly
    if (output.size() < N * N) output.resize(N * N);
    jacobi2D_impl(input, output, N);
}
